+            name: name,
+            owner: owner,
+            sortOrder: nil,
+            error: error,
+            rateLimitedUntil: rateLimitedUntil,
+            ciStatus: .unknown,
+            ciRunCount: nil,
+            openIssues: 0,
+            openPulls: 0,
+            stars: 0,
+            forks: 0,
+            pushedAt: nil,
+            latestRelease: nil,
+            latestActivity: nil,
+            activityEvents: [],
+            traffic: nil,
+            heatmap: []
+        )
+    }
 }

